const logger = createComponentLogger('RepomixCronApp');
interface ScanDirectory {
  fullPath: string;
  relativePath: string;
}
interface TypedDirectoryScanner {
  baseDir: string;
  scanDirectories(): Promise<ScanDirectory[]>;
