import { ScanResultCache, type ScanResultWithCache, type CacheStats, type RedisClient, type ScanCacheOptions } from './scan-cache.ts';
import { ScanOrchestrator, type ScanResult, type ScanConfig } from '../scan-orchestrator.ts';
import { createComponentLogger, logStart, logError, logWarn, logSkip } from '../../utils/logger.ts';
import * as Sentry from '@sentry/node';
import { TIME_MS } from '../../core/units.ts';
const logger = createComponentLogger('CachedScanner');
export interface CachedScannerOptions {
  cache?: ScanResultCache | null;
  scannerOptions?: Record<string, unknown>;
  cacheEnabled?: boolean;
  forceRefresh?: boolean;
  trackUncommitted?: boolean;
}
export interface WarmUpError {
  repository: string;
  error: string;
}
export interface WarmUpResults {
  total: number;
  successful: number;
  failed: number;
  errors: WarmUpError[];
}
export interface ScannerStats {
  cache_enabled: boolean;
  force_refresh: boolean;
  track_uncommitted: boolean;
  cache_initialized: boolean;
  cache_stats: CacheStats | null;
}
export interface CacheStatusResult {
  is_cached: boolean;
  reason?: string;
  cache_age_ms: number | null;
  cache_age_hours: number | null;
  cache_age_days: number | null;
  metadata: import('./scan-cache.ts').CacheMetadata | null;
  repository_status: RepositoryStatus;
}
export interface CachedScanOptions extends ScanConfig {
  forceRefresh?: boolean;
}
export interface CachedScanResult extends ScanResult {
  scan_metadata: ScanResult['scan_metadata'] & {
    git_status?: RepositoryStatus;
    from_cache?: boolean;
  };
  cache_metadata?: import('./scan-cache.ts').CacheMetadataAttachment;
}
export class CachedScanner {
  private readonly gitTracker: GitCommitTracker;
  private cache: ScanResultCache | null;
  private readonly scanner: ScanOrchestrator;
  private readonly cacheEnabled: boolean;
  private readonly forceRefresh: boolean;
  private readonly trackUncommitted: boolean;
  constructor(options: CachedScannerOptions = {}) {
    this.gitTracker = new GitCommitTracker();
    this.cache = options.cache ?? null;
    this.scanner = new ScanOrchestrator(options.scannerOptions ?? {});
    this.cacheEnabled = options.cacheEnabled !== false;
    this.forceRefresh = options.forceRefresh ?? false;
    this.trackUncommitted = options.trackUncommitted !== false;
    logger.info({
      cacheEnabled: this.cacheEnabled,
      forceRefresh: this.forceRefresh,
      trackUncommitted: this.trackUncommitted
    }, 'Cached scanner initialized');
  }
  initializeCache(redisClient: RedisClient, cacheOptions: ScanCacheOptions = {}): void {
    this.cache = new ScanResultCache(redisClient, {
      enabled: this.cacheEnabled,
      ...cacheOptions
    });
    logger.info('Cache initialized with Redis client');
  }
  async scanRepository(repoPath: string, options: CachedScanOptions = {}): Promise<CachedScanResult> {
    const startTime = Date.now();
    try {
      logStart(logger, 'cached repository scan', { repoPath, options });
      const repoStatus = await this.gitTracker.getRepositoryStatus(repoPath);
      const shouldUseCache = await this._shouldUseCache(repoPath, repoStatus, options);
      if (shouldUseCache) {
        const cachedResult = await this._getCachedResult(repoPath, repoStatus.current_commit);
        if (cachedResult) {
          const duration = (Date.now() - startTime) / TIME_MS.SECOND;
          logger.info({
            repoPath,
            fromCache: true,
            duration,
            cacheAge: cachedResult.cache_metadata?.age
          }, 'Scan completed from cache');
          return {
            ...cachedResult,
            scan_metadata: {
              ...cachedResult.scan_metadata,
              duration_seconds: duration,
              git_status: repoStatus
            }
          };
        }
      }
      logger.info({ repoPath, reason: options.forceRefresh ? 'forced_refresh' : 'cache_miss' }, 'Running fresh scan');
      const scanResult: ScanResult = await this.scanner.scanRepository(repoPath, options);
      if (this.cacheEnabled && this.cache && repoStatus.current_commit) {
        await this._cacheResult(repoPath, repoStatus.current_commit, scanResult);
      }
      const duration = (Date.now() - startTime) / TIME_MS.SECOND;
      logger.info({
        repoPath,
        fromCache: false,
        duration,
        duplicates: scanResult.metrics?.total_duplicate_groups ?? 0
      }, 'Scan completed from fresh scan');
      return {
        ...scanResult,
        scan_metadata: {
          ...scanResult.scan_metadata,
          duration_seconds: duration,
          git_status: repoStatus,
          from_cache: false
        }
      };
    } catch (error) {
      logError(logger, error, 'Cached scan failed', { repoPath });
      Sentry.captureException(error, {
        tags: {
          component: 'cached-scanner',
          repository: repoPath
        }
      });
      throw error;
    }
  }
  private async _shouldUseCache(
    repoPath: string,
    repoStatus: RepositoryStatus,
    options: CachedScanOptions
  ): Promise<boolean> {
    if (options.forceRefresh ?? this.forceRefresh) {
      logSkip(logger, 'cache', 'forced refresh', { repoPath });
      return false;
    }
    if (!this.cacheEnabled || !this.cache) {
      logSkip(logger, 'cache', 'caching disabled', { repoPath });
      return false;
    }
    if (!repoStatus.is_git_repository) {
      logSkip(logger, 'cache', 'not a git repository', { repoPath });
      return false;
    }
    if (this.trackUncommitted && repoStatus.has_uncommitted_changes) {
      logSkip(logger, 'cache', 'has uncommitted changes', { repoPath });
      return false;
    }
    return true;
  }
  private async _getCachedResult(
    repoPath: string,
    commitHash: string | null
  ): Promise<CachedScanResult | null> {
    try {
      const cachedResult = await this.cache!.getCachedScan(repoPath, commitHash);
      if (cachedResult) {
        const cacheAge = await this.cache!.getCacheAge(repoPath, commitHash);
        return {
          ...(cachedResult as unknown as CachedScanResult),
          cache_metadata: {
            ...cachedResult.cache_metadata,
            age: cacheAge,
            age_hours: cacheAge !== null ? cacheAge / TIME_MS.HOUR : null,
            age_days: cacheAge !== null ? cacheAge / TIME_MS.DAY : null
          }
        };
      }
      return null;
    } catch (error) {
      logWarn(logger, error as Error | null, 'Failed to get cached result', { repoPath });
      return null;
    }
  }
  private async _cacheResult(
    repoPath: string,
    commitHash: string,
    scanResult: ScanResult
  ): Promise<void> {
    try {
      await this.cache!.cacheScan(repoPath, commitHash, scanResult as unknown as ScanResultWithCache);
    } catch (error) {
      logWarn(logger, error as Error | null, 'Failed to cache scan result (non-fatal)', { repoPath });
    }
  }
  async invalidateCache(repoPath: string): Promise<number> {
    if (!this.cache) {
      logWarn(logger, null, 'Cannot invalidate cache: cache not initialized', { repoPath });
      return 0;
    }
    try {
      logger.info({ repoPath }, 'Invalidating cache for repository');
      const deletedCount = await this.cache.invalidateCache(repoPath);
      logger.info({
        repoPath,
        entriesDeleted: deletedCount
      }, 'Cache invalidated successfully');
      return deletedCount;
    } catch (error) {
      logError(logger, error, 'Failed to invalidate cache', { repoPath });
      throw error;
    }
  }
  async getCacheStatus(repoPath: string): Promise<CacheStatusResult> {
    try {
      const repoStatus = await this.gitTracker.getRepositoryStatus(repoPath);
      if (!repoStatus.current_commit) {
        return {
          is_cached: false,
          reason: 'not_a_git_repository',
          cache_age_ms: null,
          cache_age_hours: null,
          cache_age_days: null,
          metadata: null,
          repository_status: repoStatus
        };
      }
      const isCached = await this.cache?.isCached(repoPath, repoStatus.current_commit);
      const cacheAge = isCached ? await this.cache!.getCacheAge(repoPath, repoStatus.current_commit) : null;
      const metadata = isCached ? await this.cache!.getCacheMetadata(repoPath, repoStatus.current_commit) : null;
      return {
        is_cached: isCached ?? false,
        cache_age_ms: cacheAge,
        cache_age_hours: cacheAge != null ? cacheAge / TIME_MS.HOUR : null,
        cache_age_days: cacheAge != null ? cacheAge / TIME_MS.DAY : null,
        metadata,
        repository_status: repoStatus
      };
    } catch (error) {
      logError(logger, error, 'Failed to get cache status', { repoPath });
      throw error;
    }
  }
  async getStats(): Promise<ScannerStats> {
    const cacheStats = this.cache ? await this.cache.getStats() : null;
    return {
      cache_enabled: this.cacheEnabled,
      force_refresh: this.forceRefresh,
      track_uncommitted: this.trackUncommitted,
      cache_initialized: this.cache !== null,
      cache_stats: cacheStats
    };
  }
  async warmCache(repoPaths: string[], options: CachedScanOptions = {}): Promise<WarmUpResults> {
    logStart(logger, 'cache warm-up', { repositoryCount: repoPaths.length });
    const results: WarmUpResults = {
      total: repoPaths.length,
      successful: 0,
      failed: 0,
      errors: []
    };
    for (const repoPath of repoPaths) {
      try {
        await this.scanRepository(repoPath, {
          ...options,
          forceRefresh: true
        });
        results.successful++;
        logger.info({
          repoPath,
          progress: `${results.successful}/${results.total}`
        }, 'Repository scanned for cache warm-up');
      } catch (error) {
        results.failed++;
        results.errors.push({
          repository: repoPath,
          error: (error as Error).message
        });
        logError(logger, error, 'Failed to scan repository for cache warm-up', { repoPath });
      }
    }
    logger.info(results, 'Cache warm-up completed');
    return results;
  }
}import { exec } from 'child_process';
import { promisify } from 'util';
import fs from 'fs/promises';
import path from 'path';
import { createComponentLogger } from '../../utils/logger.ts';
import { TIME_MS } from '../../core/units.ts';
import { GIT, PAGINATION } from '../../core/constants.ts';
const execPromise = promisify(exec);
const logger = createComponentLogger('GitCommitTracker');
export interface CommitMetadata {
  hash: string;
  shortHash: string;
  author: string;
  email: string;
  date: string;
  message: string;
}
export interface RepositoryStatus {
  is_git_repository: boolean;
  current_commit: string | null;
  short_commit: string | null;
  branch: string | null;
  has_uncommitted_changes: boolean;
  remote_url: string | null;
  scanned_at: string;
}
export class GitCommitTracker {
  async getRepositoryCommit(repoPath: string): Promise<string | null> {
    try {
      const { stdout } = await execPromise('git rev-parse HEAD', {
        cwd: repoPath
      });
      const commitHash = stdout.trim();
      logger.info({ repoPath, commitHash }, 'Retrieved repository commit hash');
      return commitHash;
    } catch (error) {
      logger.warn({ repoPath, error: (error as Error).message }, 'Not a git repository or git not available');
      return null;
    }
  }
  async getShortCommit(repoPath: string): Promise<string | null> {
    try {
      const { stdout } = await execPromise('git rev-parse --short HEAD', {
        cwd: repoPath
      });
      const shortHash = stdout.trim();
      logger.debug({ repoPath, shortHash }, 'Retrieved short commit hash');
      return shortHash;
    } catch (error) {
      logger.warn({ repoPath, error: (error as Error).message }, 'Failed to get short commit hash');
      return null;
    }
  }
  async hasChanged(repoPath: string, lastCommit: string | null): Promise<boolean> {
    if (!lastCommit) {
      return true;
    }
    const currentCommit = await this.getRepositoryCommit(repoPath);
    if (!currentCommit) {
      logger.warn({ repoPath }, 'Cannot determine if repository changed (not a git repo)');
      return true;
    }
    const changed = currentCommit !== lastCommit;
    logger.info({
      repoPath,
      lastCommit: lastCommit.substring(0, GIT.SHORT_HASH_LENGTH),
      currentCommit: currentCommit.substring(0, GIT.SHORT_HASH_LENGTH),
      changed
    }, 'Checked repository for changes');
    return changed;
  }
  async getChangedFiles(repoPath: string, fromCommit: string | null): Promise<string[]> {
    try {
      const currentCommit = await this.getRepositoryCommit(repoPath);
      if (!currentCommit || !fromCommit) {
        logger.warn({ repoPath }, 'Cannot get changed files (missing commit hash)');
        return [];
      }
      const { stdout } = await execPromise(
        `git diff --name-only ${fromCommit} ${currentCommit}`,
        { cwd: repoPath }
      );
      const changedFiles = stdout
        .trim()
        .split('\n')
        .filter(file => file.length > 0);
      logger.info({
        repoPath,
        fromCommit: fromCommit.substring(0, GIT.SHORT_HASH_LENGTH),
        toCommit: currentCommit.substring(0, GIT.SHORT_HASH_LENGTH),
        filesChanged: changedFiles.length
      }, 'Retrieved changed files');
      return changedFiles;
    } catch (error) {
      logger.error({ repoPath, error }, 'Failed to get changed files');
      return [];
    }
  }
  async getCommitMetadata(repoPath: string, commitHash = 'HEAD'): Promise<CommitMetadata | null> {
    try {
      const { stdout } = await execPromise(
        `git show -s --format='%H|%an|%ae|%at|%s' ${commitHash}`,
        { cwd: repoPath }
      );
      const [hash, author, email, timestamp, message] = stdout.trim().split('|');
      const metadata: CommitMetadata = {
        hash,
        shortHash: hash.substring(0, GIT.SHORT_HASH_LENGTH),
        author,
        email,
        date: new Date(parseInt(timestamp) * TIME_MS.SECOND).toISOString(),
        message
      };
      logger.debug({ repoPath, metadata }, 'Retrieved commit metadata');
      return metadata;
    } catch (error) {
      logger.error({ repoPath, commitHash, error }, 'Failed to get commit metadata');
      return null;
    }
  }
  async getBranchName(repoPath: string): Promise<string | null> {
    try {
      const { stdout } = await execPromise('git rev-parse --abbrev-ref HEAD', {
        cwd: repoPath
      });
      const branchName = stdout.trim();
      logger.debug({ repoPath, branchName }, 'Retrieved branch name');
      return branchName;
    } catch (error) {
      logger.warn({ repoPath, error: (error as Error).message }, 'Failed to get branch name');
      return null;
    }
  }
  async hasUncommittedChanges(repoPath: string): Promise<boolean> {
    try {
      const { stdout } = await execPromise('git status --porcelain', {
        cwd: repoPath
      });
      const hasChanges = stdout.trim().length > 0;
      logger.info({
        repoPath,
        hasUncommittedChanges: hasChanges
      }, 'Checked for uncommitted changes');
      return hasChanges;
    } catch (error) {
      logger.warn({ repoPath, error: (error as Error).message }, 'Failed to check for uncommitted changes');
      return false;
    }
  }
  async getRemoteUrl(repoPath: string, remoteName = 'origin'): Promise<string | null> {
    try {
      const { stdout } = await execPromise(`git remote get-url ${remoteName}`, {
        cwd: repoPath
      });
      const remoteUrl = stdout.trim();
      logger.debug({ repoPath, remoteName, remoteUrl }, 'Retrieved remote URL');
      return remoteUrl;
    } catch (error) {
      logger.warn({ repoPath, remoteName, error: (error as Error).message }, 'Failed to get remote URL');
      return null;
    }
  }
  async getCommitCount(repoPath: string): Promise<number> {
    try {
      const { stdout } = await execPromise('git rev-list --count HEAD', {
        cwd: repoPath
      });
      const count = parseInt(stdout.trim());
      logger.debug({ repoPath, commitCount: count }, 'Retrieved commit count');
      return count;
    } catch (error) {
      logger.warn({ repoPath, error: (error as Error).message }, 'Failed to get commit count');
      return 0;
    }
  }
  async isGitRepository(repoPath: string): Promise<boolean> {
    try {
      const gitDir = path.join(repoPath, '.git');
      const stats = await fs.stat(gitDir);
      const isGit = stats.isDirectory();
      logger.debug({ repoPath, isGitRepository: isGit }, 'Checked if path is git repository');
      return isGit;
    } catch {
      logger.debug({ repoPath }, 'Path is not a git repository');
      return false;
    }
  }
  async getRepositoryStatus(repoPath: string): Promise<RepositoryStatus> {
    const [
      isGit,
      currentCommit,
      branchName,
      hasUncommitted,
      remoteUrl
    ] = await Promise.all([
      this.isGitRepository(repoPath),
      this.getRepositoryCommit(repoPath),
      this.getBranchName(repoPath),
      this.hasUncommittedChanges(repoPath),
      this.getRemoteUrl(repoPath)
    ]);
    const status: RepositoryStatus = {
      is_git_repository: isGit,
      current_commit: currentCommit,
      short_commit: currentCommit ? currentCommit.substring(0, GIT.SHORT_HASH_LENGTH) : null,
      branch: branchName,
      has_uncommitted_changes: hasUncommitted,
      remote_url: remoteUrl,
      scanned_at: new Date().toISOString()
    };
    logger.info({ repoPath, status }, 'Retrieved repository status');
    return status;
  }
  async getCommitHistory(repoPath: string, limit = PAGINATION.DEFAULT_QUERY_LIMIT): Promise<CommitMetadata[]> {
    try {
      const { stdout } = await execPromise(
        `git log -${limit} --format='%H|%an|%ae|%at|%s'`,
        { cwd: repoPath }
      );
      const commits = stdout
        .trim()
        .split('\n')
        .map(line => {
          const [hash, author, email, timestamp, message] = line.split('|');
          return {
            hash,
            shortHash: hash.substring(0, GIT.SHORT_HASH_LENGTH),
            author,
            email,
          date: new Date(parseInt(timestamp) * TIME_MS.SECOND).toISOString(),
            message
          };
        });
      logger.info({
        repoPath,
        commitsRetrieved: commits.length
      }, 'Retrieved commit history');
      return commits;
    } catch (error) {
      logger.error({ repoPath, error }, 'Failed to get commit history');
      return [];
    }
  }
}import { createComponentLogger, logError } from '../../utils/logger.ts';
