  commit_hash: string | null;
  short_commit: string | null;
  cached_at: string;
  ttl: number;
  scan_type: string;
  total_duplicates: number;
  total_suggestions: number;
}
export interface IndexEntry {
  cache_key: string;
  repository_path: string;
  commit_hash: string | null;
  indexed_at: string;
}
export interface CacheStats {
  total_cached_scans: number;
