const logger = createComponentLogger('MigrationAstTransformer');
export const PARSER_PLUGINS: ParserPlugin[] = [
  'typescript',
  'jsx',
  'decorators-legacy',
  'classProperties',
  'objectRestSpread',
  'asyncGenerators',
  'dynamicImport',
  'optionalChaining',
