        return new RegExp(`\\b${escaped}\\s*\\(`).test(content);
      }
      case 'remove-declaration': {
        const escaped = escapeRegExp(parsed.name);
        return new RegExp(`(?:function|const|let|var|class)\\s+${escaped}\\b`).test(content);
