const logger = createComponentLogger('RepositoryScanner');
export interface RepositoryScannerOptions {
  outputBaseDir?: string;
  codeBaseDir?: string;
  maxConcurrent?: number;
}
export interface ScanConfig {
  [key: string]: unknown;
}
export interface RepositoryInfo {
