      repoCount <= INTER_PROJECT_SCAN.SHARED_PACKAGE_MAX_REPOSITORIES
      && occurrences <= INTER_PROJECT_SCAN.SHARED_PACKAGE_MAX_OCCURRENCES
    ) {
