}
class SchemaEnhancementPipeline extends BasePipeline<SchemaEnhancementWorker> {
  private excludeDirs: Set<string>;
  private baseDir: string;
  private options: SchemaEnhancementOptions;
  constructor(options: SchemaEnhancementOptions = {}) {
    super(new SchemaEnhancementWorker({
      ...options,
      maxConcurrent: config.maxConcurrent ?? CONCURRENCY.DEFAULT_IO_BOUND,
      logDir: config.logDir,
      sentryDsn: config.sentryDsn,
      gitWorkflowEnabled: options.gitWorkflowEnabled ?? config.enableGitWorkflow,
      gitBranchPrefix: options.gitBranchPrefix || 'docs',
      gitBaseBranch: options.gitBaseBranch || config.gitBaseBranch,
      gitDryRun: options.gitDryRun ?? config.gitDryRun,
      outputBaseDir: options.outputBaseDir || './document-enhancement-impact-measurement',
      dryRun: options.dryRun || false,
    }));
    this.options = options;
    this.excludeDirs = new Set([
      'node_modules',
      '.git',
      'dist',
      'build',
      'coverage',
      'venv',
      '__pycache__'
    ]);
    this.baseDir = options.baseDir || config.codeBaseDir || config.homeDir;
    this.setupDefaultEventListeners(logger, {
      onCreated: (job) => ({ readmePath: (job.data as Record<string, unknown>).relativePath }),
      onStarted: (job) => ({ readmePath: (job.data as Record<string, unknown>).relativePath }),
      onCompleted: (job) => {
        const result = job.result as Record<string, unknown>;
        const impact = result.impact as Record<string, unknown> | undefined;
        return { status: result.status, schemaType: result.schemaType, impactScore: impact?.impactScore };
      },
      onFailed: (job) => ({ readmePath: (job.data as Record<string, unknown>).relativePath }),
    });
  }
  async scanForReadmes(dir: string, baseDir: string = dir, results: ReadmeFile[] = []): Promise<ReadmeFile[]> {
    try {
      const entries = await fs.readdir(dir, { withFileTypes: true });
      for (const entry of entries) {
        const fullPath = path.join(dir, entry.name);
        if (entry.isDirectory()) {
          if (this.excludeDirs.has(entry.name)) {
            continue;
          }
          await this.scanForReadmes(fullPath, baseDir, results);
        } else if (entry.name === 'README.md') {
          const relativePath = path.relative(baseDir, fullPath);
          results.push({
            fullPath,
            relativePath,
            name: entry.name,
            dirPath: path.dirname(fullPath)
          });
        }
      }
    } catch (error) {
      logger.error({ dir, error: error instanceof Error ? error.message : String(error) }, 'Error scanning directory');
    }
    return results;
  }
  async scanDirectory(directory: string): Promise<ReadmeFile[]> {
    logger.info({ directory }, 'Scanning for README files');
    const readmeFiles = await this.scanForReadmes(directory);
    logger.info({
      readmeFiles: readmeFiles.length
    }, 'Directory scan complete');
    return readmeFiles;
  }
  async createEnhancementJobs(readmeFiles: ReadmeFile[]): Promise<void> {
    const context = {
      totalReadmes: readmeFiles.length,
      baseDir: this.baseDir
    };
    for (const readme of readmeFiles) {
      const repoContext: RepoContext = {
        ...context,
        hasPackageJson: false,
        hasPyproject: false,
        gitRemote: null
      };
      await this.worker.createEnhancementJob(readme, repoContext);
    }
    logger.info({ jobsCreated: readmeFiles.length }, 'Enhancement jobs created');
  }
  async runEnhancement(directory: string = this.baseDir): Promise<EnhancementResult> {
    logStart(logger, 'schema enhancement pipeline', { directory });
    const startTime = Date.now();
    try {
      const readmeFiles = await this.scanDirectory(directory);
      if (readmeFiles.length === 0) {
        logger.warn({ directory }, 'No README files found');
        return {
          status: 'completed',
          readmesFound: 0,
          enhanced: 0
        };
      }
      await this.createEnhancementJobs(readmeFiles);
      await this.waitForCompletion();
      const duration = Date.now() - startTime;
      const stats = this.worker.getEnhancementStats();
      const jobStats = this.getStats();
      await this.worker.generateSummaryReport();
      logger.info({
        duration,
        stats,
        jobStats
      }, 'Schema enhancement pipeline completed');
      return {
        status: 'completed',
        duration,
        ...stats,
        jobs: jobStats
      };
    } catch (error) {
      logError(logger, error, 'Schema enhancement pipeline failed');
      throw error;
    }
  }
  scheduleEnhancements(cronSchedule: string = '0 3 * * 0') {
    return this.scheduleCron(logger, 'schema enhancement', cronSchedule, () => this.runEnhancement());
  }
}
if (isDirectExecution(import.meta.url)) {
  const cronSchedule = process.env.SCHEMA_ENHANCEMENT_CRON_SCHEDULE || '0 3 * * 0';
  const args = process.argv.slice(PROCESS.ARGV_START);
  const options: SchemaEnhancementOptions = {
    dryRun: false,
    gitWorkflowEnabled: config.enableGitWorkflow
  };
  let directory: string = config.codeBaseDir || config.homeDir;
  let runNow = config.runOnStartup;
  for (let i = 0; i < args.length; i++) {
    if (args[i] === '--run-now' || args[i] === '--run') {
      runNow = true;
    } else if (args[i] === '--dry-run') {
      options.dryRun = true;
    } else if (args[i] === '--dir' && args[i + 1]) {
      directory = args[i + 1];
      i++;
    } else if (args[i] === '--git-workflow') {
      options.gitWorkflowEnabled = true;
    } else if (args[i] === '--no-git-workflow') {
      options.gitWorkflowEnabled = false;
    }
  }
  const pipeline = new SchemaEnhancementPipeline(options);
  if (runNow) {
    logger.info({ directory, options }, 'Running schema enhancement immediately');
    pipeline.runEnhancement(directory)
      .then((result) => {
        logger.info({ result }, 'Enhancement completed successfully');
        process.exit(0);
      })
      .catch((error: unknown) => {
        logError(logger, error, 'Enhancement failed');
        process.exit(1);
      });
  } else {
    logStart(logger, 'schema enhancement pipeline in scheduled mode', { cronSchedule });
    pipeline.scheduleEnhancements(cronSchedule);
    logger.info('Schema enhancement pipeline running. Press Ctrl+C to stop.');
  }
}
export { SchemaEnhancementPipeline };import test from 'node:test';
import assert from 'node:assert/strict';
import fs from 'fs/promises';
import os from 'os';
import path from 'path';
import { spawn } from 'child_process';
import { fileURLToPath } from 'url';
interface ScriptRunResult {
  code: number | null;
  signal: NodeJS.Signals | null;
  stdout: string;
  stderr: string;
  timedOut: boolean;
}
const TEST_TIMEOUT_MS = 15_000;
const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const REPO_ROOT = path.resolve(__dirname, '..');
const envSensitiveTest = process.env.SKIP_ENV_SENSITIVE_TESTS === '1'
  ? test.skip
  : test;
async function runScript(
  scriptRelativePath: string,
  args: string[],
  envOverrides: Record<string, string>,
  timeoutMs: number = TEST_TIMEOUT_MS
): Promise<ScriptRunResult> {
  return await new Promise((resolve, reject) => {
    const child = spawn(
      process.execPath,
      ['--strip-types', path.join(REPO_ROOT, scriptRelativePath), ...args],
      {
        cwd: REPO_ROOT,
        env: { ...process.env, ...envOverrides },
        stdio: ['ignore', 'pipe', 'pipe']
      }
    );
    let stdout = '';
    let stderr = '';
    let settled = false;
    let timedOut = false;
    child.stdout.on('data', (chunk) => {
      stdout += String(chunk);
    });
    child.stderr.on('data', (chunk) => {
      stderr += String(chunk);
    });
    const timeout = setTimeout(() => {
      timedOut = true;
      child.kill('SIGKILL');
    }, timeoutMs);
    child.on('error', (error) => {
      if (settled) return;
      settled = true;
      clearTimeout(timeout);
      reject(error);
    });
    child.on('exit', (code, signal) => {
      if (settled) return;
      settled = true;
      clearTimeout(timeout);
      resolve({ code, signal, stdout, stderr, timedOut });
    });
  });
}
