import path from 'path';
import os from 'os';
import { FORMATTING, LIMITS } from '../core/constants.ts';
import { createComponentLogger, logWarn } from './logger.ts';
const logger = createComponentLogger('DirectoryScanner');
interface DirectoryScannerOptions {
  baseDir?: string;
  outputDir?: string;
  excludeDirs?: string[];
  maxDepth?: number;
}
interface ScannedDirectory {
  fullPath: string;
  relativePath: string;
  name: string;
  depth: number;
  isGitRepo: boolean;
}
interface ScanStats {
  total: number;
  byDepth: Record<number, number>;
  totalSize: number;
  byName: Record<string, number>;
  topDirectoryNames?: Array<{ name: string; count: number }>;
}
interface ScanReport {
  timestamp: string;
  baseDir: string;
  scanStats: ScanStats;
  directories: Array<{ relativePath: string; name: string; depth: number }>;
}
interface ScanSummary {
  timestamp: string;
  baseDir: string;
  totalDirectories: number;
  maxDepth: number;
  reportPath: string;
  treePath: string;
  stats: ScanStats;
}
interface DirectoryInfo {
  path: string;
  size: number;
  fileCount: number;
  modifiedAt: Date;
}
export class DirectoryScanner {
  baseDir: string;
  outputDir: string;
  excludeDirs: Set<string>;
  maxDepth: number;
  constructor(options: DirectoryScannerOptions = {}) {
    this.baseDir = options.baseDir ?? path.join(os.homedir(), 'code');
    this.outputDir = options.outputDir ?? './directory-scan-reports';
    this.excludeDirs = new Set(options.excludeDirs ?? [
      'node_modules',
      '.git',
      'dist',
      'build',
      'coverage',
      '.next',
      '.nuxt',
      'vendor',
      '__pycache__',
      '.venv',
      'venv',
      'jobs',
      'logs',
      '.claude',
      'python',
      'node',
      'go',
      'php',
      'rust',
      'recovery',
    ]);
    this.maxDepth = options.maxDepth ?? LIMITS.DEFAULT_MAX_DEPTH;
  }
  async scanDirectories(): Promise<ScannedDirectory[]> {
    const directories: ScannedDirectory[] = [];
    await this.scanRecursive(this.baseDir, '', 0, directories);
    return directories;
  }
  /**
   * Check if a directory is a git repository root
   */
  async isGitRepository(dirPath: string): Promise<boolean> {
    try {
      const gitPath = path.join(dirPath, '.git');
      const stat = await fs.stat(gitPath);
      return stat.isDirectory();
    } catch {
      return false;
    }
  }
  async scanRecursive(currentPath: string, relativePath: string, depth: number, results: ScannedDirectory[]): Promise<void> {
    if (depth > this.maxDepth) {
      return;
    }
    try {
      const isGitRepo = await this.isGitRepository(currentPath);
      if (isGitRepo) {
        results.push({
          fullPath: currentPath,
          relativePath: relativePath || path.basename(currentPath),
          name: path.basename(currentPath),
          depth,
          isGitRepo: true,
        });
        logger.info({ path: currentPath, relativePath }, 'Found git repository');
        return;
      }
      const entries = await fs.readdir(currentPath, { withFileTypes: true });
      for (const entry of entries) {
        if (!entry.isDirectory()) continue;
        if (this.excludeDirs.has(entry.name)) {
          continue;
        }
        if (entry.name.startsWith('.')) {
          continue;
        }
        const fullPath = path.join(currentPath, entry.name);
        const newRelativePath = relativePath
          ? path.join(relativePath, entry.name)
          : entry.name;
        await this.scanRecursive(fullPath, newRelativePath, depth + 1, results);
      }
    } catch (error) {
      logWarn(logger, null, 'Cannot access directory', { path: currentPath, errorMessage: (error as Error).message });
    }
  }
  async shouldProcess(dirPath: string): Promise<boolean> {
    try {
      const stat = await fs.stat(dirPath);
      if (!stat.isDirectory()) return false;
      const entries = await fs.readdir(dirPath);
      return entries.length > 0;
    } catch {
      return false;
    }
  }
  async getDirectoryInfo(dirPath: string): Promise<DirectoryInfo> {
    const stat = await fs.stat(dirPath);
    const entries = await fs.readdir(dirPath);
    return {
      path: dirPath,
      size: stat.size,
      fileCount: entries.length,
      modifiedAt: stat.mtime,
    };
  }
  generateScanStats(directories: ScannedDirectory[]): ScanStats {
    const stats: ScanStats = {
      total: directories.length,
      byDepth: {},
      totalSize: 0,
      byName: {},
    };
    for (const dir of directories) {
      stats.byDepth[dir.depth] = (stats.byDepth[dir.depth] ?? 0) + 1;
      stats.byName[dir.name] = (stats.byName[dir.name] ?? 0) + 1;
    }
    const sortedNames = Object.entries(stats.byName)
      .sort((a, b) => b[1] - a[1])
      .slice(0, LIMITS.DISPLAY_TOP_N);
    stats.topDirectoryNames = sortedNames.map(([name, count]) => ({ name, count }));
    return stats;
  }
  async saveScanReport(directories: ScannedDirectory[], stats: ScanStats): Promise<string> {
    await fs.mkdir(this.outputDir, { recursive: true });
    const timestamp = Date.now();
    const report: ScanReport = {
      timestamp: new Date().toISOString(),
      baseDir: this.baseDir,
      scanStats: stats,
      directories: directories.map(d => ({
        relativePath: d.relativePath,
        name: d.name,
        depth: d.depth,
      })),
    };
    const reportPath = path.join(this.outputDir, `scan-report-${timestamp}.json`);
    await fs.writeFile(reportPath, JSON.stringify(report, null, FORMATTING.JSON_INDENT));
    return reportPath;
  }
  generateDirectoryTree(directories: ScannedDirectory[]): string {
    const tree: string[] = [];
    tree.push('Directory Tree:');
    tree.push('==============');
    tree.push('');
    tree.push(this.baseDir);
    for (const dir of directories) {
      const indent = '  '.repeat(dir.depth + 1);
      const prefix = dir.depth === 0 ? '├── ' : '└── ';
      tree.push(`${indent}${prefix}${dir.name}/`);
    }
    return tree.join('\n');
  }
  async saveDirectoryTree(directories: ScannedDirectory[]): Promise<string> {
    await fs.mkdir(this.outputDir, { recursive: true });
    const tree = this.generateDirectoryTree(directories);
    const timestamp = Date.now();
    const treePath = path.join(this.outputDir, `directory-tree-${timestamp}.txt`);
    await fs.writeFile(treePath, tree);
    return treePath;
  }
  async generateAndSaveScanResults(directories: ScannedDirectory[]): Promise<{
    summary: ScanSummary;
    reportPath: string;
    treePath: string;
    summaryPath: string;
  }> {
    const stats = this.generateScanStats(directories);
    const reportPath = await this.saveScanReport(directories, stats);
    const treePath = await this.saveDirectoryTree(directories);
    const summary: ScanSummary = {
      timestamp: new Date().toISOString(),
      baseDir: this.baseDir,
      totalDirectories: directories.length,
      maxDepth: directories.length > 0 ? Math.max(...directories.map(d => d.depth)) : 0,
      reportPath,
      treePath,
      stats,
    };
    const summaryPath = path.join(this.outputDir, `scan-summary-${Date.now()}.json`);
    await fs.writeFile(summaryPath, JSON.stringify(summary, null, FORMATTING.JSON_INDENT));
    return {
      summary,
      reportPath,
      treePath,
      summaryPath,
    };
  }
}import { createComponentLogger, logError } from './logger.ts';
import { CONFIG_POLICY, MAX_SCORE, TIMEOUTS, RETRY, CACHE, FORMATTING } from '../core/constants.ts';
import Sentry from '@sentry/node';
import fs from 'fs/promises';
import path from 'path';
import os from 'os';
const logger = createComponentLogger('DopplerResilience');
const CircuitState = {
  CLOSED: 'CLOSED',
  OPEN: 'OPEN',
  HALF_OPEN: 'HALF_OPEN'
} as const;
type CircuitStateType = typeof CircuitState[keyof typeof CircuitState];
interface DopplerResilienceOptions {
  failureThreshold?: number;
  successThreshold?: number;
  timeout?: number;
  maxBackoffMs?: number;
  baseDelayMs?: number;
  backoffMultiplier?: number;
  cacheFile?: string;
  staleThresholdMs?: number;
}
interface ResilienceMetrics {
  totalRequests: number;
  totalFailures: number;
  totalSuccesses: number;
  currentBackoffMs: number;
  lastError: { message: string; timestamp: string } | null;
}
interface HealthStatus {
  healthy: boolean;
  circuitState: CircuitStateType;
  failureCount: number;
  consecutiveFailures: number;
  successCount: number;
  lastFailureTime: string | null;
  lastSuccessTime: string | null;
  nextAttemptTime: string | null;
  waitTimeMs: number;
  currentBackoffMs: number;
  metrics: {
    totalRequests: number;
    totalFailures: number;
    totalSuccesses: number;
    successRate: string;
    lastError: { message: string; timestamp: string } | null;
  };
  usingFallback: boolean;
  cacheLoadedAt: string | null;
}
export abstract class DopplerResilience {
  failureThreshold: number;
  successThreshold: number;
  timeout: number;
  maxBackoffMs: number;
  baseDelayMs: number;
  backoffMultiplier: number;
  state: CircuitStateType;
  failureCount: number;
  successCount: number;
  lastFailureTime: number | null;
  lastSuccessTime: number | null;
  consecutiveFailures: number;
  nextAttemptTime: number | null;
  cacheFile: string;
  cachedSecrets: Record<string, unknown> | null;
  cacheLoadedAt: number | null;
  staleThresholdMs: number;
  metrics: ResilienceMetrics;
  constructor(options: DopplerResilienceOptions = {}) {
    this.failureThreshold = options.failureThreshold ?? CONFIG_POLICY.DOPPLER.DEFAULT_FAILURE_THRESHOLD;
    this.successThreshold = options.successThreshold ?? CONFIG_POLICY.DOPPLER.DEFAULT_SUCCESS_THRESHOLD;
    this.timeout = options.timeout ?? TIMEOUTS.SHORT_MS;
    this.maxBackoffMs = options.maxBackoffMs ?? RETRY.MAX_BACKOFF_MS;
    this.baseDelayMs = options.baseDelayMs ?? RETRY.BASE_BACKOFF_MS;
    this.backoffMultiplier = options.backoffMultiplier ?? RETRY.BACKOFF_MULTIPLIER;
    this.staleThresholdMs = options.staleThresholdMs ?? CACHE.STALE_THRESHOLD_MS;
    this.state = CircuitState.CLOSED;
    this.failureCount = 0;
    this.successCount = 0;
    this.lastFailureTime = null;
    this.lastSuccessTime = null;
    this.consecutiveFailures = 0;
    this.nextAttemptTime = null;
    this.cacheFile = options.cacheFile ?? path.join(os.homedir(), '.doppler', '.fallback.json');
    this.cachedSecrets = null;
    this.cacheLoadedAt = null;
    this.metrics = {
      totalRequests: 0,
      totalFailures: 0,
      totalSuccesses: 0,
      currentBackoffMs: 0,
      lastError: null
    };
  }
  async getSecrets(): Promise<Record<string, unknown>> {
    this.metrics.totalRequests++;
    if (this.state === CircuitState.OPEN) {
      if (this.nextAttemptTime === null) {
        logger.warn('Circuit OPEN with null nextAttemptTime — resetting to HALF_OPEN');
        this.state = CircuitState.HALF_OPEN;
        this.successCount = 0;
      } else if (Date.now() >= this.nextAttemptTime) {
        logger.info('Circuit breaker timeout elapsed, attempting HALF_OPEN state');
        this.state = CircuitState.HALF_OPEN;
        this.successCount = 0;
      } else {
        const waitMs = this.nextAttemptTime - Date.now();
        logger.warn({
          state: this.state,
          waitMs,
          failureCount: this.failureCount
        }, 'Circuit breaker OPEN, using cached secrets');
        return await this.getFallbackSecrets();
      }
    }
    try {
      const secrets = await this.fetchFromDoppler();
      this.handleSuccess();
      return secrets;
    } catch (error) {
      this.handleFailure(error as Error);
      return await this.getFallbackSecrets();
    }
  }
  abstract fetchFromDoppler(): Promise<Record<string, unknown>>;
  async getFallbackSecrets(): Promise<Record<string, unknown>> {
    try {
      if (!this.cachedSecrets || this.isCacheStale()) {
        logger.info({ cacheFile: this.cacheFile }, 'Loading fallback secrets from cache');
        const cacheContent = await fs.readFile(this.cacheFile, 'utf-8');
        this.cachedSecrets = JSON.parse(cacheContent);
        this.cacheLoadedAt = Date.now();
        logger.info('Fallback secrets loaded successfully');
      }
    } catch (error) {
      logError(logger, error, 'Failed to load fallback secrets', { cacheFile: this.cacheFile });
      Sentry.captureException(error, {
        tags: {
          component: 'doppler-resilience',
          operation: 'get-fallback-secrets'
        },
        extra: {
          cacheFile: this.cacheFile,
          circuitState: this.state
        }
      });
      throw new Error(`Doppler API unavailable and no fallback cache: ${(error as Error).message}`);
    }
    if (!this.cachedSecrets) {
      throw new Error('Cache load appeared to succeed but cachedSecrets is null');
    }
    return this.cachedSecrets;
  }
  isCacheStale(): boolean {
    if (!this.cacheLoadedAt) return true;
    const cacheAgeMs = Date.now() - this.cacheLoadedAt;
    const staleThresholdMs = this.staleThresholdMs;
    return cacheAgeMs > staleThresholdMs;
  }
  handleSuccess(): void {
    this.lastSuccessTime = Date.now();
    this.consecutiveFailures = 0;
    this.metrics.totalSuccesses++;
    this.metrics.currentBackoffMs = 0;
    if (this.state === CircuitState.HALF_OPEN) {
      this.successCount++;
      logger.info({
        successCount: this.successCount,
        threshold: this.successThreshold
      }, 'Success in HALF_OPEN state');
      if (this.successCount >= this.successThreshold) {
        this.state = CircuitState.CLOSED;
        this.failureCount = 0;
        this.successCount = 0;
        logger.info('Circuit breaker CLOSED - service recovered');
        Sentry.captureMessage('Doppler circuit breaker recovered', {
          level: 'info',
          tags: {
            component: 'doppler-resilience',
            circuitState: 'CLOSED'
          }
        });
      }
    } else if (this.state === CircuitState.CLOSED) {
      this.failureCount = 0;
    }
  }
  handleFailure(error: Error): void {
    this.lastFailureTime = Date.now();
    this.failureCount++;
    this.consecutiveFailures++;
    this.metrics.totalFailures++;
    this.metrics.lastError = {
      message: error.message,
      timestamp: new Date().toISOString()
    };
    const backoffMs = Math.min(
      this.baseDelayMs * Math.pow(this.backoffMultiplier, this.consecutiveFailures - 1),
      this.maxBackoffMs
    );
    this.metrics.currentBackoffMs = backoffMs;
    logger.warn({
      error: error.message,
      failureCount: this.failureCount,
      consecutiveFailures: this.consecutiveFailures,
      backoffMs,
      state: this.state
    }, 'Doppler API call failed');
    if (this.state === CircuitState.HALF_OPEN) {
      this.state = CircuitState.OPEN;
      this.nextAttemptTime = Date.now() + this.timeout;
      logger.warn({
        nextAttemptTime: new Date(this.nextAttemptTime).toISOString()
      }, 'Circuit breaker reopened due to failure in HALF_OPEN state');
      Sentry.captureMessage('Doppler circuit breaker reopened', {
        level: 'warning',
        tags: {
          component: 'doppler-resilience',
          circuitState: 'OPEN'
        },
        extra: {
          failureCount: this.failureCount,
          nextAttemptTime: new Date(this.nextAttemptTime).toISOString()
        }
      });
    } else if (this.state === CircuitState.CLOSED && this.failureCount >= this.failureThreshold) {
      this.state = CircuitState.OPEN;
      this.nextAttemptTime = Date.now() + this.timeout;
      logger.error({
        failureCount: this.failureCount,
        threshold: this.failureThreshold,
        nextAttemptTime: new Date(this.nextAttemptTime).toISOString()
      }, 'Circuit breaker OPEN - failure threshold exceeded');
      Sentry.captureException(error, {
        level: 'error',
        tags: {
          component: 'doppler-resilience',
          circuitState: 'OPEN'
        },
        extra: {
          failureCount: this.failureCount,
          failureThreshold: this.failureThreshold,
          consecutiveFailures: this.consecutiveFailures,
          backoffMs
        }
      });
    }
  }
  getHealth(): HealthStatus {
    const now = Date.now();
    return {
      healthy: this.state === CircuitState.CLOSED,
      circuitState: this.state,
      failureCount: this.failureCount,
      consecutiveFailures: this.consecutiveFailures,
      successCount: this.successCount,
      lastFailureTime: this.lastFailureTime
        ? new Date(this.lastFailureTime).toISOString()
        : null,
      lastSuccessTime: this.lastSuccessTime
        ? new Date(this.lastSuccessTime).toISOString()
        : null,
      nextAttemptTime: this.nextAttemptTime
        ? new Date(this.nextAttemptTime).toISOString()
        : null,
      waitTimeMs: this.nextAttemptTime
        ? Math.max(0, this.nextAttemptTime - now)
        : 0,
      currentBackoffMs: this.metrics.currentBackoffMs,
      metrics: {
        totalRequests: this.metrics.totalRequests,
        totalFailures: this.metrics.totalFailures,
        totalSuccesses: this.metrics.totalSuccesses,
        successRate: this.metrics.totalRequests > 0
          ? (this.metrics.totalSuccesses / this.metrics.totalRequests * MAX_SCORE).toFixed(FORMATTING.DECIMAL_PLACES) + '%'
          : 'N/A',
        lastError: this.metrics.lastError
      },
