const logger = createComponentLogger('RefactorTestSuite');
interface RefactorConfig {
  projectPath: string;
  testsDir: string;
  utilsDir: string;
  e2eDir: string;
  framework: 'vitest' | 'jest' | 'playwright';
}
interface AnalysisResult {
  testFiles: string[];
