  } = options;
  if (!jobId || !jobType || !status) {
    throw new Error('Missing required fields: jobId, jobType, status');
  }
  const timestamp = new Date().toISOString().replace(/[:.]/g, '-').slice(0, -5);
  const baseName = `${jobType}-${timestamp}`;
