    return `
    <section class="results">
        <h2>📊 Results</h2>
        <p class="empty-state">No results available</p>
    </section>`;
  }
  const resultObj = result as Record<string, unknown>;
  const metrics = extractMetrics(resultObj);
  const details = extractDetails(resultObj);
  return `
