      minDiskSpace: BYTES_PER_KB * BYTES_PER_KB * LIMITS.MIN_DISK_SPACE_MB,
      maxLogSize: LIMITS.MAX_BUFFER_MB * BYTES_PER_KB * BYTES_PER_KB
