        cwd: this.dashboardDir,
        timeout: TIMEOUTS.FIVE_MINUTES_MS,
        env: { ...process.env, FORCE_COLOR: '0' },
      });
      const stepTimings = this.#parseTimings(stdout);
      const endTime = Date.now();
      const output: PopulateOutput = {
        seed,
        dryRun,
        skipJudge,
        skipSync,
        limit,
        steps: stepTimings,
        durationMs: endTime - startTime,
        stdout: stdout.slice(-(2 * LIMITS.MAX_OUTPUT_CHARS)),
        stderr: stderr.slice(-LIMITS.MAX_OUTPUT_CHARS),
        timestamp: new Date().toISOString(),
      };
      logger.info({
        jobId: job.id,
        durationMs: output.durationMs,
        steps: stepTimings.length,
      }, 'Dashboard populate job completed');
      const reportPaths = await generateReport({
        jobId: job.id,
        jobType: 'dashboard-populate',
        status: 'completed',
        result: output,
        startTime,
        endTime,
        parameters: job.data,
        metadata: { steps: stepTimings },
      });
      output.reportPaths = reportPaths;
      return output;
    } catch (error) {
      logger.error({
        jobId: job.id,
        error: (error as Error).message,
        stderr: (error as { stderr?: string }).stderr?.slice(-LIMITS.MAX_OUTPUT_CHARS),
      }, 'Dashboard populate job failed');
      Sentry.captureException(error, {
        tags: {
          component: 'dashboard-populate-worker',
          job_id: job.id,
        },
        extra: { seed, dryRun, skipJudge, skipSync },
      });
      throw error;
    }
  }
  #parseTimings(stdout: string): StepTiming[] {
    const timings: StepTiming[] = [];
    const lines = stdout.split('\n');
    for (const line of lines) {
      const match = line.match(/^\s{2}(\S+)\s+(\d+)ms$/);
      if (match && match[1] !== 'total') {
        timings.push({ name: match[1], ms: parseInt(match[2], NUMBER_BASE.DECIMAL) });
      }
    }
    return timings;
