import { createComponentLogger } from '../utils/logger.ts';
import { TIMEOUTS, GIT_ACTIVITY, NUMBER_BASE } from '../core/constants.ts';
import { TIME_MS } from '../core/units.ts';
const logger = createComponentLogger('GitActivityWorker');
interface GitActivityWorkerOptions extends SidequestServerOptions {
  codeBaseDir?: string;
  pythonScript?: string;
  personalSiteDir?: string;
  outputDir?: string;
}
interface PythonArgs {
  reportType?: string;
  days?: number;
  sinceDate?: string;
  untilDate?: string;
  outputFormat?: string;
  generateVisualizations?: boolean;
}
interface PythonScriptResult {
  stdout: string;
  stderr: string;
  outputFiles: string[];
}
export interface GitActivityStats {
  totalCommits: number;
  totalRepositories: number;
  linesAdded: number;
  linesDeleted: number;
  filesChanged?: number;
}
interface VerifiedFile {
  path: string;
  size?: number;
  exists: boolean;
}
interface ReportJobOptions {
  jobId?: string;
  reportType?: string;
  days?: number;
  sinceDate?: string;
  untilDate?: string;
  outputFormat?: string;
  generateVisualizations?: boolean;
}
function toFiniteNumber(value: unknown): number {
  if (typeof value === 'number' && Number.isFinite(value)) {
    return value;
  }
  if (typeof value === 'string') {
    const parsed = Number(value);
    if (Number.isFinite(parsed)) {
      return parsed;
    }
  }
  return 0;
}
export function buildGitActivityStatsFromData(data: Record<string, unknown>): GitActivityStats {
  return {
    totalCommits: toFiniteNumber(data.total_commits),
    totalRepositories: Array.isArray(data.repositories)
      ? data.repositories.length
      : toFiniteNumber(data.total_repositories),
    linesAdded: toFiniteNumber(data.total_additions),
    linesDeleted: toFiniteNumber(data.total_deletions),
    filesChanged: toFiniteNumber(data.total_files),
  };
}
export async function parseGitActivityStatsFromJsonFiles(
  outputFiles: string[],
  scriptDir: string,
  readFile: (path: string, encoding: BufferEncoding) => Promise<string> = fs.readFile
): Promise<GitActivityStats | null> {
  const jsonFiles = outputFiles.filter((file) => file.toLowerCase().endsWith('.json'));
  for (const file of jsonFiles) {
    const resolvedPath = path.isAbsolute(file)
      ? file
      : path.resolve(scriptDir, file);
    try {
      const content = await readFile(resolvedPath, 'utf-8');
      const data = JSON.parse(content) as Record<string, unknown>;
      if (Object.prototype.hasOwnProperty.call(data, 'total_commits')) {
        return buildGitActivityStatsFromData(data);
      }
    } catch (error) {
      const err = error as Error;
      logger.warn({ file: resolvedPath, error: err.message }, 'Failed to parse git activity stats JSON file');
      Sentry.captureException(err, {
        tags: {
          component: 'git-activity-worker',
          operation: 'parse-stats-json',
        },
        extra: {
          file: resolvedPath,
        },
      });
    }
  }
  return null;
}
export function parseGitActivityStatsFromText(stdout: string): GitActivityStats {
  const stats: GitActivityStats = {
    totalCommits: 0,
    totalRepositories: 0,
    linesAdded: 0,
    linesDeleted: 0,
  };
  const commitsMatch = stdout.match(/Total commits:\s*(\d+)/i);
  if (commitsMatch) {
    stats.totalCommits = parseInt(commitsMatch[1], NUMBER_BASE.DECIMAL);
  }
  const additionsMatch = stdout.match(/Lines added:\s*(\d+)/i);
  if (additionsMatch) {
    stats.linesAdded = parseInt(additionsMatch[1], NUMBER_BASE.DECIMAL);
  }
  const deletionsMatch = stdout.match(/Lines deleted:\s*(\d+)/i);
  if (deletionsMatch) {
    stats.linesDeleted = parseInt(deletionsMatch[1], NUMBER_BASE.DECIMAL);
  }
  const reposMatch = stdout.match(/Active repositories:\s*(\d+)/i);
  if (reposMatch) {
    stats.totalRepositories = parseInt(reposMatch[1], NUMBER_BASE.DECIMAL);
  }
  const filesMatch = stdout.match(/File changes:\s*(\d+)/i);
  if (filesMatch) {
    stats.filesChanged = parseInt(filesMatch[1], NUMBER_BASE.DECIMAL);
  }
  return stats;
}
export class GitActivityWorker extends SidequestServer {
  codeBaseDir: string;
  pythonScript: string;
  personalSiteDir: string;
  outputDir: string;
  constructor(options: GitActivityWorkerOptions = {}) {
    super({
      ...options,
      jobType: 'git-activity',
    });
    this.codeBaseDir = options.codeBaseDir ?? path.join(os.homedir(), 'code');
    const moduleDir = path.dirname(fileURLToPath(import.meta.url));
    this.pythonScript = options.pythonScript ?? path.join(
      moduleDir,
      '..',
      'pipeline-runners',
      'collect_git_activity.py'
    );
    this.personalSiteDir = options.personalSiteDir ?? path.join(
      os.homedir(),
      'code',
      'PersonalSite'
    );
    this.outputDir = options.outputDir ?? path.join(os.homedir(), 'code', 'PersonalSite', '_reports');
  }
  async runJobHandler(job: Job): Promise<unknown> {
    const startTime = Date.now();
    const {
      reportType,
      days,
      sinceDate,
      untilDate,
      outputFormat = 'both',
      generateVisualizations = true
    } = job.data as {
      reportType?: string;
      days?: number;
      sinceDate?: string;
      untilDate?: string;
      outputFormat?: string;
      generateVisualizations?: boolean;
    };
    logger.info({
      jobId: job.id,
      reportType,
      days,
      sinceDate,
      untilDate
    }, 'Running git activity report');
    try {
      const args = this.#buildPythonArgs({
        reportType,
        days,
        sinceDate,
        untilDate,
        outputFormat,
        generateVisualizations
      });
      const { stdout, stderr, outputFiles } = await this.#runPythonScript(args);
      if (stderr) {
        logger.warn({ jobId: job.id, stderr }, 'Git activity warnings');
      }
      const stats = await this.#parseStats(stdout, outputFiles);
      const verifiedFiles = await this.#verifyOutputFiles(outputFiles);
      logger.info({
        jobId: job.id,
        stats,
        filesGenerated: verifiedFiles.length
      }, 'Git activity report completed');
      const result: Record<string, unknown> = {
        reportType,
        days: days ?? this.#calculateDays(sinceDate, untilDate),
        sinceDate,
        untilDate,
        stats,
        outputFiles: verifiedFiles,
        timestamp: new Date().toISOString(),
      };
      const endTime = Date.now();
      const reportPaths = await generateReport({
        jobId: job.id,
        jobType: 'git-activity',
        status: 'completed',
        result,
        startTime,
        endTime,
        parameters: job.data,
        metadata: {
          reportType,
          filesGenerated: verifiedFiles.length
        }
      });
      result.reportPaths = reportPaths;
      logger.info({ reportPaths }, 'Git activity reports generated');
      return result;
    } catch (error) {
      const err = error as Error;
      logger.error({
        jobId: job.id,
        error: err.message,
        stack: err.stack
      }, 'Git activity report failed');
      throw error;
    }
  }
  #buildPythonArgs({ reportType, days, sinceDate, untilDate, outputFormat, generateVisualizations }: PythonArgs): string[] {
    const args: string[] = [];
    if (sinceDate) {
      args.push('--start-date', sinceDate);
      if (untilDate) {
        args.push('--end-date', untilDate);
      }
    } else if (reportType === GIT_ACTIVITY.WEEKLY_REPORT_TYPE || days === GIT_ACTIVITY.WEEKLY_WINDOW_DAYS) {
      args.push('--weekly');
    } else if (reportType === GIT_ACTIVITY.MONTHLY_REPORT_TYPE || days === GIT_ACTIVITY.MONTHLY_WINDOW_DAYS) {
      args.push('--monthly');
    } else if (days) {
      args.push('--days', String(days));
    } else {
      args.push('--weekly');
    }
    if (outputFormat) {
      args.push('--output-format', outputFormat);
    }
    if (!generateVisualizations) {
      args.push('--no-visualizations');
    }
    return args;
  }
  #runPythonScript(args: string[]): Promise<PythonScriptResult> {
    return new Promise((resolve, reject) => {
      logger.debug({ args }, 'Executing Python script');
      const proc = spawn('python3', [this.pythonScript, ...args], {
        cwd: path.dirname(this.pythonScript),
        timeout: TIMEOUTS.GIT_REPORT_MS,
      });
      const output = captureProcessOutput(proc);
      proc.on('close', (code) => {
        const stdout = output.getStdout();
        const stderr = output.getStderr();
        if (code === 0) {
          const outputFiles = this.#extractOutputFiles(stdout);
          resolve({ stdout, stderr, outputFiles });
        } else {
          const error = new Error(`Python script exited with code ${code}`) as Error & {
            code: number | null;
            stdout: string;
            stderr: string;
          };
          error.code = code;
          error.stdout = stdout;
          error.stderr = stderr;
          reject(error);
        }
      });
      proc.on('error', (error) => {
        const augmented = error as Error & { stdout: string; stderr: string };
        augmented.stdout = output.getStdout();
        augmented.stderr = output.getStderr();
        reject(augmented);
      });
    });
  }
  #extractOutputFiles(stdout: string): string[] {
    const files = new Set<string>();
    const pendingSvgBasenames: string[] = [];
    const jsonPatterns = [
      /JSON data saved to:\s*(.+\.json)/gi,
      /(?:Saving|Saved)\s+(?:to|data to):\s*(.+\.json)/gi,
    ];
    for (const pattern of jsonPatterns) {
      for (const match of stdout.matchAll(pattern)) {
        files.add(match[1].trim());
      }
    }
    for (const match of stdout.matchAll(/Jekyll report saved to:\s*(.+\.md)/gi)) {
      files.add(match[1].trim());
    }
    for (const match of stdout.matchAll(/(?:Generating|Generated|Saving|Created).*?:\s*(.+\.svg)/gi)) {
      const rawPath = match[1].trim();
      if (path.isAbsolute(rawPath) || rawPath.includes('/')) {
        files.add(rawPath);
      } else {
        pendingSvgBasenames.push(rawPath);
      }
    }
    const visualizationDirMatch = stdout.match(/Visualizations saved to:\s*(.+)/i);
    if (visualizationDirMatch) {
      const visualizationDir = visualizationDirMatch[1].trim();
      for (const svgName of pendingSvgBasenames) {
        files.add(path.join(visualizationDir, svgName));
      }
    }
    return Array.from(files);
  }
  async #parseStats(stdout: string, outputFiles: string[]): Promise<GitActivityStats> {
    const scriptDir = path.dirname(this.pythonScript);
    const jsonStats = await parseGitActivityStatsFromJsonFiles(outputFiles, scriptDir);
    if (jsonStats) {
      return jsonStats;
    }
    return parseGitActivityStatsFromText(stdout);
  }
  #calculateDays(sinceDate?: string, untilDate?: string): number | null {
    if (!sinceDate || !untilDate) return null;
    const since = new Date(sinceDate);
    const until = new Date(untilDate);
    const diffTime = Math.abs(until.getTime() - since.getTime());
    const diffDays = Math.ceil(diffTime / TIME_MS.DAY);
    return diffDays;
  }
  async #verifyOutputFiles(files: string[]): Promise<VerifiedFile[]> {
    const verified: VerifiedFile[] = [];
    const scriptDir = path.dirname(this.pythonScript);
    for (const file of files) {
      const resolvedPath = path.isAbsolute(file)
        ? file
        : path.resolve(scriptDir, file);
      try {
        await fs.access(resolvedPath);
        const stats = await fs.stat(resolvedPath);
        verified.push({
          path: resolvedPath,
          size: stats.size,
          exists: true,
        });
      } catch (error) {
        const err = error as Error;
        logger.warn({ file: resolvedPath, error: err.message }, 'Output file not found');
        verified.push({
          path: resolvedPath,
          exists: false,
        });
      }
    }
    return verified;
  }
  createWeeklyReportJob(): Job {
    const jobId = `git-activity-weekly-${Date.now()}`;
    return this.createJob(jobId, {
      reportType: GIT_ACTIVITY.WEEKLY_REPORT_TYPE,
      days: GIT_ACTIVITY.WEEKLY_WINDOW_DAYS,
      outputFormat: 'both',
      type: 'git-activity-report',
    });
  }
  createMonthlyReportJob(): Job {
    const jobId = `git-activity-monthly-${Date.now()}`;
    return this.createJob(jobId, {
      reportType: GIT_ACTIVITY.MONTHLY_REPORT_TYPE,
      days: GIT_ACTIVITY.MONTHLY_WINDOW_DAYS,
      outputFormat: 'both',
      type: 'git-activity-report',
    });
  }
  createCustomReportJob(sinceDate: string, untilDate: string): Job {
    const jobId = `git-activity-custom-${Date.now()}`;
    return this.createJob(jobId, {
      reportType: GIT_ACTIVITY.CUSTOM_REPORT_TYPE,
      sinceDate,
      untilDate,
      type: 'git-activity-report',
    });
  }
  createReportJob(options: ReportJobOptions = {}): Job {
    const jobId = options.jobId ?? `git-activity-${Date.now()}`;
    return this.createJob(jobId, {
      reportType: options.reportType ?? GIT_ACTIVITY.DEFAULT_REPORT_TYPE,
      days: options.days,
      sinceDate: options.sinceDate,
      untilDate: options.untilDate,
      outputFormat: options.outputFormat ?? 'both',
      generateVisualizations: options.generateVisualizations !== false,
      type: 'git-activity-report',
    });
  }
}import { SidequestServer, type Job, type SidequestServerOptions } from '../core/server.ts';
import { GitignoreRepomixUpdater } from '../utils/gitignore-repomix-updater.ts';
import { generateReport } from '../utils/report-generator.ts';
import { createComponentLogger } from '../utils/logger.ts';
import { LIMITS } from '../core/constants.ts';
import * as Sentry from '@sentry/node';
import path from 'path';
import os from 'os';
const logger = createComponentLogger('GitignoreWorker');
interface GitignoreWorkerOptions extends SidequestServerOptions {
  baseDir?: string;
  excludeDirs?: string[];
  maxDepth?: number;
  gitignoreEntry?: string;
}
interface GitignoreJobData {
  baseDir?: string;
  excludeDirs?: string[];
  maxDepth?: number;
  gitignoreEntry?: string;
  dryRun?: boolean;
  repositories?: string[] | null;
  type?: string;
}
interface RepositoryResult {
  repository: string;
  action: string;
  reason?: string;
  [key: string]: unknown;
}
interface ProcessSummary {
  added: number;
  skipped: number;
  would_add: number;
  error: number;
  [key: string]: unknown;
}
interface ProcessResults {
  totalRepositories: number;
  results: RepositoryResult[];
  summary: ProcessSummary;
}
interface GitignoreUpdateResult extends ProcessResults {
  timestamp: string;
  dryRun: boolean;
  gitignoreEntry: string;
  reportPaths?: unknown;
}
interface UpdateJobOptions {
  baseDir?: string;
  dryRun?: boolean;
  gitignoreEntry?: string;
  excludeDirs?: string[];
  maxDepth?: number;
  repositories?: string[];
}
export class GitignoreWorker extends SidequestServer {
  baseDir: string;
  excludeDirs: string[];
  maxDepth: number;
  gitignoreEntry: string;
  constructor(options: GitignoreWorkerOptions = {}) {
    super({
      ...options,
      jobType: 'gitignore-manager',
    });
    this.baseDir = options.baseDir ?? path.join(os.homedir(), 'code');
    this.excludeDirs = options.excludeDirs ?? [
      'node_modules',
      '.git',
      'dist',
      'build',
      'coverage',
      '.next',
      '.nuxt',
      'vendor',
      '__pycache__',
      '.venv',
      'venv',
    ];
    this.maxDepth = options.maxDepth ?? LIMITS.DEFAULT_MAX_DEPTH;
    this.gitignoreEntry = options.gitignoreEntry ?? 'repomix-output.xml';
  }
  async runJobHandler(job: Job): Promise<GitignoreUpdateResult> {
    const startTime = Date.now();
    const {
      baseDir = this.baseDir,
      excludeDirs = this.excludeDirs,
      maxDepth = this.maxDepth,
      gitignoreEntry = this.gitignoreEntry,
      dryRun = false,
      repositories = null,
    } = job.data as unknown as GitignoreJobData;
    logger.info({
      jobId: job.id,
      baseDir,
      dryRun,
      specificRepos: repositories ? repositories.length : 'all'
    }, 'Running gitignore update job');
    try {
      const updater = new GitignoreRepomixUpdater({
        baseDir,
        excludeDirs,
        maxDepth,
        dryRun,
      });
      if (gitignoreEntry) {
        updater.gitignoreEntry = gitignoreEntry;
      }
      let results: ProcessResults;
      if (repositories && repositories.length > 0) {
        results = await this.processSpecificRepositories(updater, repositories);
      } else {
        results = await updater.processRepositories() as unknown as ProcessResults;
      }
      logger.info({
        jobId: job.id,
        totalRepositories: results.totalRepositories,
        added: results.summary.added,
        skipped: results.summary.skipped,
        wouldAdd: results.summary.would_add,
        errors: results.summary.error
      }, 'Gitignore update job completed');
      const result: GitignoreUpdateResult = {
        ...results,
        timestamp: new Date().toISOString(),
        dryRun,
        gitignoreEntry,
      };
      const endTime = Date.now();
      const reportPaths = await generateReport({
        jobId: job.id,
        jobType: 'gitignore-update',
        status: 'completed',
        result,
        startTime,
        endTime,
        parameters: job.data,
        metadata: {
          totalRepositories: results.totalRepositories,
          dryRun
        }
      });
      result.reportPaths = reportPaths;
      logger.info({ reportPaths }, 'Gitignore update reports generated');
      return result;
    } catch (error) {
      logger.error({
        jobId: job.id,
        error: (error as Error).message,
        stack: (error as Error).stack
      }, 'Gitignore update job failed');
      Sentry.captureException(error, {
        tags: {
          component: 'gitignore-worker',
          job_id: job.id,
        },
        extra: {
          baseDir,
          dryRun,
          gitignoreEntry,
        },
      });
      throw error;
    }
  }
  private async processSpecificRepositories(updater: GitignoreRepomixUpdater, repositories: string[]): Promise<ProcessResults> {
    const results: RepositoryResult[] = [];
    logger.info({
      count: repositories.length
    }, 'Processing specific repositories');
    for (const repoPath of repositories) {
      logger.info({ repository: repoPath }, 'Processing repository');
      const result = await updater.addToGitignore(repoPath) as unknown as { action: string; reason?: string; [key: string]: unknown };
      results.push({
        repository: repoPath,
        ...result,
      });
      logger.info({
        repository: repoPath,
        action: result.action,
        reason: result.reason
      }, 'Repository processed');
    }
    return {
      totalRepositories: repositories.length,
      results,
      summary: updater.generateSummary(results as unknown as Parameters<typeof updater.generateSummary>[0]) as unknown as ProcessSummary,
    };
  }
  createUpdateAllJob(options: UpdateJobOptions = {}): Job {
    const jobId = `gitignore-update-all-${Date.now()}`;
    return this.createJob(jobId, {
      type: 'gitignore-update',
      baseDir: options.baseDir ?? this.baseDir,
      dryRun: options.dryRun ?? false,
      gitignoreEntry: options.gitignoreEntry ?? this.gitignoreEntry,
      excludeDirs: options.excludeDirs ?? this.excludeDirs,
      maxDepth: options.maxDepth ?? this.maxDepth,
    });
  }
  createUpdateRepositoriesJob(repositories: string[], options: UpdateJobOptions = {}): Job {
    const jobId = `gitignore-update-repos-${Date.now()}`;
    return this.createJob(jobId, {
      type: 'gitignore-update',
      repositories,
      dryRun: options.dryRun ?? false,
      gitignoreEntry: options.gitignoreEntry ?? this.gitignoreEntry,
    });
  }
  createDryRunJob(options: UpdateJobOptions = {}): Job {
    const jobId = `gitignore-dryrun-${Date.now()}`;
    return this.createJob(jobId, {
      type: 'gitignore-update',
      baseDir: options.baseDir ?? this.baseDir,
      dryRun: true,
      gitignoreEntry: options.gitignoreEntry ?? this.gitignoreEntry,
      excludeDirs: options.excludeDirs ?? this.excludeDirs,
      maxDepth: options.maxDepth ?? this.maxDepth,
    });
  }
}import test from 'node:test';
import assert from 'node:assert/strict';
import fs from 'fs/promises';
import os from 'os';
import path from 'path';
