        jobId: job.id,
        error: (error as Error).message,
        stack: (error as Error).stack,
      }, 'Repository cleanup job failed');
      Sentry.captureException(error, {
        tags: {
          component: 'repo-cleanup-worker',
          job_id: job.id,
        },
        extra: {
          targetDir,
          dryRun,
        },
      });
      throw error;
    }
